from dataclasses import dataclass

# Claude Opus approximate pricing per million tokens (USD)
INPUT_COST_PER_M  = 15.0
OUTPUT_COST_PER_M = 75.0

@dataclass
class TokenUsage:
    input_tokens: int
    output_tokens: int
    cache_read_input_tokens: int = 0
    cache_creation_input_tokens: int = 0

    @property
    def total_tokens(self) -> int:
        return self.input_tokens + self.output_tokens

    def cost_usd(self) -> float:
        # Cache reads are cheaper (10% of input price for Opus)
        billable_input = self.input_tokens - self.cache_read_input_tokens
        cache_cost = self.cache_read_input_tokens * (INPUT_COST_PER_M * 0.10) / 1_000_000
        return (
            billable_input * INPUT_COST_PER_M / 1_000_000
            + self.output_tokens * OUTPUT_COST_PER_M / 1_000_000
            + cache_cost
        )

def extract_usage(response) -> TokenUsage:
    u = response.usage
    return TokenUsage(
        input_tokens=u.input_tokens,
        output_tokens=u.output_tokens,
        cache_read_input_tokens=getattr(u, "cache_read_input_tokens", 0),
        cache_creation_input_tokens=getattr(u, "cache_creation_input_tokens", 0),
    )

from statistics import median

EFFICIENCY_MULTIPLIER = 2.0  # flag if steps > baseline * multiplier

class EfficiencyBaseline:
    def __init__(self) -> None:
        self._baselines: dict[str, list[int]] = {}

    def record(self, task_category: str, tool_call_count: int) -> None:
        self._baselines.setdefault(task_category, []).append(tool_call_count)

    def baseline(self, task_category: str) -> float | None:
        records = self._baselines.get(task_category)
        return median(records) if records else None

    def is_inefficient(self, task_category: str, tool_call_count: int) -> bool:
        base = self.baseline(task_category)
        if base is None:
            return False
        return tool_call_count > base * EFFICIENCY_MULTIPLIER

import time
from statistics import median, quantiles

def measure_request_latency(fn, *args, **kwargs) -> tuple:
    """Wrap a function call and return (result, latency_ms)."""
    start = time.perf_counter()
    result = fn(*args, **kwargs)
    latency_ms = (time.perf_counter() - start) * 1000
    return result, latency_ms

class LatencyTracker:
    def __init__(self) -> None:
        self._samples: list[float] = []

    def record(self, latency_ms: float) -> None:
        self._samples.append(latency_ms)

    def stats(self) -> dict:
        if not self._samples:
            return {}
        qs = quantiles(self._samples, n=100)
        return {
            "p50_ms":  qs[49],
            "p95_ms":  qs[94],
            "p99_ms":  qs[98],
            "median_ms": median(self._samples),
            "samples": len(self._samples),
        }

