# Mark the system prompt for caching using cache_control
def build_cached_system_prompt(base_instructions: str, tool_docs: str) -> list[dict]:
    """
    Build a system prompt with cache_control on the stable portions.
    The first call creates the cache; subsequent calls within 5 minutes
    read from it at 10% of the input token price.
    """
    return [
        {
            "type": "text",
            "text": base_instructions,
            "cache_control": {"type": "ephemeral"},
        },
        {
            "type": "text",
            "text": tool_docs,
            "cache_control": {"type": "ephemeral"},
        },
    ]

def cost_with_cache(usage: TokenUsage) -> float:
    """
    Compute actual cost accounting for cache reads and cache creation.
    Cache creation is 25% MORE than normal input price; reads are 10%.
    """
    normal_input = (
        usage.input_tokens
        - usage.cache_read_input_tokens
        - usage.cache_creation_input_tokens
    )
    return (
        normal_input * INPUT_COST_PER_M / 1_000_000
        + usage.cache_creation_input_tokens * INPUT_COST_PER_M * 1.25 / 1_000_000
        + usage.cache_read_input_tokens * INPUT_COST_PER_M * 0.10 / 1_000_000
        + usage.output_tokens * OUTPUT_COST_PER_M / 1_000_000
    )

def cache_hit_rate(usage: TokenUsage) -> float:
    """Fraction of input tokens served from cache."""
    return (
        usage.cache_read_input_tokens / usage.input_tokens
        if usage.input_tokens > 0 else 0.0
    )

COST_WARNING_THRESHOLD_USD   = 0.05   # warn if mean cost > $0.05/request
LATENCY_WARNING_MS           = 8_000  # warn if p95 latency > 8s
REDUNDANCY_WARNING_RATE      = 0.10   # warn if >10% of calls are redundant

def ci_efficiency_report(scorecard: EfficiencyScorecard) -> None:
    print(scorecard.report())
    warnings = []
    if scorecard.total_cost_usd > COST_WARNING_THRESHOLD_USD:
        warnings.append(
            f"[WARN] Cost ${scorecard.total_cost_usd:.4f} exceeds threshold ${COST_WARNING_THRESHOLD_USD}"
        )
    if scorecard.total_tool_calls > 0:
        redundancy_rate = scorecard.redundant_calls / scorecard.total_tool_calls
        if redundancy_rate > REDUNDANCY_WARNING_RATE:
            warnings.append(
                f"[WARN] Redundancy rate {redundancy_rate:.0%} exceeds {REDUNDANCY_WARNING_RATE:.0%}"
            )
    if scorecard.total_latency_ms > LATENCY_WARNING_MS:
        warnings.append(
            f"[WARN] Latency {scorecard.total_latency_ms:.0f}ms exceeds {LATENCY_WARNING_MS}ms"
        )
    for w in warnings:
        print(w)
    if not warnings:
        print("[OK] All efficiency metrics within thresholds")
